import React, { useState, useEffect } from 'react';
import './App.css';
import AOS from 'aos';
import LottieAnimation from './components/animation'
import animationData from './resources/animation_lkuowbyo.json';
import lottie from 'lottie-web';
import 'aos/dist/aos.css';
import Lenis from '@studio-freight/lenis'
import { RingLoader } from 'react-spinners'; // Removed PropagateLoader since it's not used
import GradientWrapper from './GradientWrapper';
import { faAngleDown } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Navbar from './components/Navbar';
import FirstSection from './components/FirstSection';
import SecondSection from './components/SecondSection';
import ThirdSection from './components/ThirdSection';
import FourthSection from './components/FourthSection';
import ButtonsHolder from './components/ButtonsHolder';
import Title from './components/Title';

function App() {
  const [loading, setLoading] = useState(true);


  // Simulate loading for 1 second
  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 2500);

    return () => clearTimeout(timer);
  }, []);

  // Initialize Lenis
  const lenis = new Lenis()

  lenis.on('scroll', (e) => {
    console.log(e)
  })

  function raf(time) {
    lenis.raf(time)
    requestAnimationFrame(raf)
  }

  requestAnimationFrame(raf)

  AOS.init();

  return (
    <div className="App">
      <div className={`loading-spinner ${loading ? '' : 'hidden'}`}>
        <LottieAnimation style={{position: 'relative', height: '500px', width: '500px'}} src={require('./resources/animation_lkvhjvhi.json')} />
      </div>
      
      {!loading && (
        <>
          <Navbar />
          <GradientWrapper />
          <div className="rowmenucontainer">
            <div className="arrow bounce">
              <i className="fa fa-angle-down fa-5x" aria-hidden="true">
                <FontAwesomeIcon icon={faAngleDown} />
              </i>
            </div>
            <Title />
            <ButtonsHolder />
          </div>
          <div className="sections">
            <FirstSection />
            <LottieAnimation src={require('./resources/animation_lkuowbyo.json')} />
            <SecondSection />
            <LottieAnimation style={{position: 'relative', height: '200px', transform: 'scaleX(-1)', left: '-23vw'}} src={require('./resources/animation_lkuowbyo.json')}/>
            <ThirdSection />
            <LottieAnimation style={{position: 'relative', left: '-3vw'}} src={require('./resources/animation_lkuowbyo.json')} />
            <FourthSection />
          </div>
        </>
      )}
    </div>
  );
}

export default App;
